SELECT COUNT(DISTINCT state_id)
FROM stacks
WHERE stack_operation = 'pop';

SELECT input_string
FROM input_sets
WHERE input_set_id = 0;

SELECT stack_operation
FROM stacks
WHERE state_id = 1;

SELECT 
    (SELECT COUNT(DISTINCT input_string) FROM input_sets) AS total_distinct_inputs,
    (SELECT COUNT(DISTINCT user_id) FROM access_logs) AS total_distinct_users;

SELECT v.*
FROM versions v
JOIN fsm f ON v.fsm_id = f.fsm_id;

SELECT *
FROM input_sets
WHERE input_set_id NOT IN (SELECT input_set_id FROM simulations);
